      "data: { billing_provider: string; customer_id: string; configuration?: object; delivery_method?: 'direct_to_billing_provider' | 'aws_sqs' | 'tackle' | 'aws_sns'; delivery_method_id?: string; tax_provider?: 'anrok' | 'avalara' | 'stripe'; }[];",
