        example:
          'package main\n\nimport (\n\t"context"\n\t"fmt"\n\t"time"\n\n\t"github.com/Metronome-Industries/metronome-go"\n\t"github.com/Metronome-Industries/metronome-go/option"\n)\n\nfunc main() {\n\tclient := metronome.NewClient(\n\t\toption.WithBearerToken("My Bearer Token"),\n\t)\n\tpage, err := client.V1.Usage.ListWithGroups(context.TODO(), metronome.V1UsageListWithGroupsParams{\n\t\tBillableMetricID: "222796fd-d29c-429e-89b2-549fabda4ed6",\n\t\tCustomerID:       "04ca7e72-4229-4a6e-ab11-9f7376fccbcb",\n\t\tWindowSize:       metronome.V1UsageListWithGroupsParamsWindowSize("day"),\n\t\tEndingBefore:     metronome.Time(time.Now()),\n\t\tGroupFilters: map[string][]string{\n\t\t\t"region": {"us-east1", "us-west1"},\n\t\t},\n\t\tGroupKey:   []string{"region"},\n\t\tStartingOn: metronome.Time(time.Now()),\n\t})\n\tif err != nil {\n\t\tpanic(err.Error())\n\t}\n\tfmt.Printf("%+v\\n", page)\n}\n',
